import { useEffect, useState } from "react";
import axios from "axios";
import Api from "../api/Api";

export default function SupervisorDashboard() {
  const [locations, setLocations] = useState([]);
  const [search, setSearch] = useState("");
  const [selectedLocation, setSelectedLocation] = useState(null);

  const [priority, setPriority] = useState("Medium");
  const [showDropdown, setShowDropdown] = useState(false);

  const [allRequests, setAllRequests] = useState([]);
  const [myRequests, setMyRequests] = useState([]);

  const supervisorId = localStorage.getItem("id");

  useEffect(() => {
    getLocations();
    getAllRequests();
    getMyRequests();
  }, []);

  // ================= LOCATIONS =================
  const getLocations = async () => {
    try {
      const res = await axios.get(Api.get_All_Locations);
      setLocations(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  // ================= ALL REQUESTS =================
  const getAllRequests = async () => {
    try {
      const res = await axios.get(Api.get_All_Emg_Req);

      const data = res.data?.data || res.data || [];
      setAllRequests(Array.isArray(data) ? data : []);
    } catch (err) {
      console.log(err);
      setAllRequests([]);
    }
  };

  // ================= MY REQUESTS =================
  const getMyRequests = async () => {
    try {
      const res = await axios.get(
        `${Api.get_My_Emg_Req}/${supervisorId}`
      );
     console.log(res.data.data);
      const data = res.data?.data || res.data || [];
      setMyRequests(Array.isArray(data) ? data : []);
    } catch (err) {
      console.log(err);
      setMyRequests([]);
    }
  };

  // ================= CREATE REQUEST =================
const handleSubmit = async () => {
  try {
    if (!selectedLocation) {
      return alert("Please select location");
    }

    const res = await axios.post(Api.create_Emg_Req, {
      requestedBy: supervisorId,
      location: selectedLocation._id,
      priority,
    });

    alert(res.data.message || "Request Created Successfully");

    getAllRequests();
    getMyRequests();

    // reset UI
    setSelectedLocation(null);
    setSearch("");
    setPriority("Medium");
    setShowDropdown(false);

  } catch (err) {
    console.log(err);

    alert(
      err.response?.data?.message ||
      "This location already has an active request"
    );
  }
};

  const steps = ["Pending", "Accepted", "Scheduled", "Arrived", "Completed"];

  return (

    <div className="min-h-screen bg-gray-100 p-6">
        <div className="text-center mb-10">
          

          <h1 className="text-4xl font-bold text-gray-800">
            Supervisor Dashboard
          </h1>
        </div>

      {/* ================= CREATE ================= */}
      <div className="max-w-2xl mx-auto bg-white p-6 rounded-xl shadow">

        <h1 className="text-2xl font-bold mb-4">
          Create Emergency Request
        </h1>

        <input
          className="w-full border p-2 rounded"
          placeholder="Search location"
          value={search}
          onChange={(e) => {
            setSearch(e.target.value);
            setShowDropdown(true);
          }}
        />

        {showDropdown && (
          <div className="border mt-2 max-h-40 overflow-y-auto bg-white">
            {locations
              .filter((l) =>
                l.location.toLowerCase().includes(search.toLowerCase())
              )
              .map((loc) => (
                <div
                  key={loc._id}
                  onClick={() => {
                    setSelectedLocation(loc);
                    setSearch(loc.location);
                    setShowDropdown(false);
                  }}
                  className="p-2 hover:bg-gray-200 cursor-pointer"
                >
                  {loc.location}
                </div>
              ))}
          </div>
        )}

        {selectedLocation && (
          <p className="text-green-600 mt-2">
            Selected: {selectedLocation.location}
          </p>
        )}

        {/* PRIORITY */}
        <div className="flex gap-3 mt-4">
          {["Low", "Medium", "High"].map((p) => (
            <button
              key={p}
              onClick={() => setPriority(p)}
              className={`px-4 py-2 rounded ${
                priority === p
                  ? "bg-green-600 text-white"
                  : "bg-gray-200"
              }`}
            >
              {p}
            </button>
          ))}
        </div>

        <button
          onClick={handleSubmit}
          className="w-full mt-4 bg-blue-600 text-white py-2 rounded"
        >
          Submit Request
        </button>
      </div>

      {/* ================= MY REQUESTS ================= */}
    

      {/* ================= ALL REQUESTS ================= */}
      <div className="max-w-4xl mx-auto mt-6 bg-white p-6 rounded-xl shadow">

        <h2 className="text-xl font-bold mb-4">
          All Requests
        </h2>

        {allRequests.length === 0 ? (
          <p>No requests found</p>
        ) : (
          allRequests.map((req) => (
            <div key={req._id} className="border p-3 mb-2 rounded">

              <p>📍 {req.location?.location}</p>
              <p>Priority: {req.priority}</p>

              {/* STATUS ONLY (timeline not needed here) */}
              <p className="font-bold text-blue-600">
                {req.status}
              </p>

            </div>
          ))
        )}
      </div>

    </div>
  );
}
